#include <bits/stdc++.h>
using namespace std;

int T, n, t, m, a[5005], x;

bool cmp(int a, int b) {
    return a > b;
}

int main() {
    cin >> T;
    while (T--) {
        cin >> n >> t >> m;
        for (int i = 1; i <= n; i++) {
            cin >> a[i];
        }
        for (int i = 1; i <= m; i++) {
            cin >> x;
            a[x] -= 2;
        }
        int cnt = 0;
        sort(a + 1, a + n + 1, cmp);
        for (int i = 1; i <= n; i++) {
            // printf("%d %d ", a[i], t);
            if (a[i] > 0) {
                cnt++;
            }
            else {
                if (t >= (1 - a[i])) {
                    // printf("%d ", (1 - a[i]));
                    t -= (1 - a[i]);
                    a[i] = 1;
                    // printf("%d ", t);
                    cnt++;
                }
                else {
                    break;
                }
            }
            // cout << endl;
        }
        cout << cnt << endl;
    }
    return 0;
}
